logger.error("Source exclusion roles: " + JSON.stringify(source));
var sourceRoleIds = source.RoleId;
var resultArray = [];
try {
    var uniqueRoles = Array.from(new Set(sourceRoleIds.split(",").map(function(item) { return item.trim(); })));
    // Process each unique role
    uniqueRoles.forEach(function(sourceRoleId) {
        var roleResponse = openidm.query(
            "managed/alpha_role",
            {
                "_queryFilter": 'businessRoleId eq "' + sourceRoleId + '"'
            },
            ["_id"]
        );
        if (roleResponse.result && roleResponse.result.length > 0) {
            var roleId = roleResponse.result[0]._id;
            var roleRef = { "_ref": "managed/alpha_role/" + roleId };
            resultArray.push(roleRef);
        }
    });
} catch (e) {
    logger.error("Exception occurred: " + e);
}
resultArray;

